import './Post.css'
import React, {useState, useEffect} from 'react'
import { Link, useParams, useNavigate } from 'react-router-dom'
import axios from "axios";
import {MoreVert} from "@mui/icons-material";
import {Users} from '../../seeds/Seeds'

const PostContent = ({post}) => {

      const [like, setLike] = useState(post.like)
      const [liked, setLiked] = useState(false)

      const [dislike, setDislike] = useState(post.dislike)
      const [disliked, setDisliked] = useState(false)

      const likeHandler = () => {
        setLike(liked ? like -1 : like +1)
        setLiked(!liked)
      }

      const dislikeHandler = () => {
        setDislike(disliked ? dislike -1 : dislike +1)
        setDisliked(!disliked)
      }

      const initialState = {
        status_body : "",
        date : "",
        file : "",
      };


      const navigate = useNavigate();
      const [formData, setFormData] = useState(initialState);

      const handleChange = (e) => {
        console.log(e.target);
        setFormData({ ...formData, [e.target.id]: e.target.value });
      };


      const handleSubmit = (e) => {
        e.preventDefault();
        const media = new FormData();
        media.append("file", formData.file);
        media.append("name", formData.name);
        media.append("status_body", formData.status_body);
        media.append("date", formData.date);

        console.log(formData)
        axios.post("http://localhost:8000/bunnybook/posts/", media).then((res) => {
          console.log(media)
          setFormData(initialState);
          addPost(res.data);
          navigate("/posts", { replace: true });
        });
      };

      const handleFile = (e) => {
        console.log(e.target);
        setFormData({ ...formData, [e.target.id]: e.target.files[0] });
      };



  return (
    <div className="content">
<div className="cwrapper">
    <div className="ctop">
    <div className="topleft">
    <img className="cpic" alt='profilepic' src={Users.filter((u) => u.id === post.id)[0].profilePicture}/>
    <span className="cusername">{Users.filter((u) => u.id === post.id)[0].username}</span>

    <span className="cdate">{post.date}</span>
    </div>
    <div className="topright"></div>

<MoreVert />
    </div>
    <div className="ccenter">
    <span className="ctext">{post.status_body}</span>
    <img className="cimg" alt='' src={post.file} />
    </div>
    <div className="cbottom">
<div className="cbottomleft">
<img className="cicon" alt='iconpic' src='/assets/icons/like.png' onClick={likeHandler} />
<img className="cicon" alt='iconpic' src='/assets/icons/dislike.png' onClick={dislikeHandler} />
<span className="like">{like} liked</span>
<span className="dislike">{dislike} disliked</span>
</div>
<div className="cbottomright">
<span className="commenttext">{post.comments} comments</span>
</div>
    </div>
</div>


    </div>
  )
}

export default PostContent
